INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Learning Objectives', 'text', '{"body": "## What you will learn\n\nBy the end of this module you will be able to:\n\n- Explain what Medicaid is and how it differs from Medicare\n- Describe how Medicaid funds Home and Community-Based Services (HCBS)\n- Identify the role of Utah DSPD in coordinating waiver services\n- Recognize why accurate service delivery and documentation protects funding\n- Apply Medicaid compliance principles to your daily DSP role"}'::jsonb, 0, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'What Is Medicaid?', 'text', '{"body": "## A joint federal\u2013state program\n\nMedicaid is a public health insurance program jointly funded by the federal government and each state. It pays for medical care and long-term services and supports (LTSS) for people who meet financial and disability criteria.\n\n## Key facts\n\n- Largest single payer of long-term services in the United States\n- Administered in Utah by the Department of Health & Human Services (DHHS)\n- For people with intellectual/developmental disabilities (IDD) and acquired brain injury (ABI), the DSPD coordinates the day-to-day services Medicaid pays for\n- Without Medicaid funding, most of the people you support could not afford the services that keep them living in their community"}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Medicaid vs. Medicare', 'text', '{"body": "## Don''t confuse the two\n\n- Medicaid \u2192 needs-based; pays for long-term supports, personal care, residential habilitation, day services, respite\n- Medicare \u2192 age/disability-based federal insurance; pays for medical care for people 65+ or with certain disabilities; does NOT generally pay for long-term personal care or DSP services\n\nMany people you support are dually eligible \u2014 they have both. Medicaid is what funds your paycheck and the supports the person receives at home."}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'HCBS Waivers Explained', 'text', '{"body": "## Home and Community-Based Services\n\nHistorically, Medicaid only paid for care delivered in institutions (nursing facilities, ICF/IIDs). HCBS waivers let states ''waive'' that rule so people can receive the same level of support in their own home or community.\n\n## Utah DSPD operates several waivers\n\n- Community Supports Waiver (CSW) \u2014 IDD adults & children\n- Acquired Brain Injury Waiver (ABI)\n- Physical Disabilities Waiver\n- Community Transitions Waiver\n\nEach waiver has its own eligibility, service menu, and rules \u2014 but they all share the HCBS Settings Rule and DSPD provider standards."}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Who Pays For Your Work', 'text', '{"body": "## Follow the money\n\n1. CMS sends federal matching dollars to Utah\n2. Utah DHHS / DSPD contracts with provider agencies (your employer)\n3. Your agency bills Medicaid for the services you deliver and document\n4. Medicaid pays the agency only for services that are: authorized in the person''s plan, actually delivered, and properly documented\n\nIf a service is billed without being delivered or documented, that is Medicaid fraud \u2014 a federal crime."}'::jsonb, 4, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Medicaid Fraud is a Federal Offense', 'callout', '{"variant": "critical", "title": "Medicaid Fraud is a Federal Offense", "body": "Billing for services not delivered, falsifying time, or signing notes for another DSP can result in: termination, repayment of funds, civil penalties up to $11,000 per claim, and criminal prosecution. **Document only what you actually did, on the day you did it.**"}'::jsonb, 5, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Person-Centered Service Plan (PCSP)', 'text', '{"body": "## The plan drives the billing\n\nEvery individual on a waiver has a Person-Centered Service Plan (sometimes called Support Plan or ISP). It lists:\n\n- The person''s goals and outcomes\n- Authorized services and units (hours per week/month)\n- The provider responsible for each service\n- Backup plans and risk mitigation strategies\n\nYour daily notes must connect to the goals in the plan."}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Documentation Standards', 'text', '{"body": "## Medicaid documentation must be:\n\n- **Timely** \u2014 written the same day the service was provided\n- **Specific** \u2014 name the goal worked on, what you did, how the person responded\n- **Accurate** \u2014 actual start/end times, not rounded estimates\n- **Signed** \u2014 your name, title, date\n- **Legible** \u2014 typed or clearly handwritten in ink\n\nIf it isn''t documented, in the eyes of Medicaid it didn''t happen."}'::jsonb, 7, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'What Would You Do?', 'scenario', '{"prompt": "Your co-worker asks you to sign her timesheet for yesterday''s shift because she forgot. She says she really did work the hours.", "context": "Both of you are paid through Medicaid waiver funds.", "choices": [{"label": "Sign it \u2014 she really did work", "correct": false, "feedback": "Signing for another worker is falsification of a Medicaid record \u2014 fraud, regardless of intent."}, {"label": "Tell her she must sign it herself and contact her supervisor", "correct": true, "feedback": "Correct. Only the person who performed the work may sign."}, {"label": "Sign it but write a note saying she really worked", "correct": false, "feedback": "Still falsification."}]}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Your Role in Protecting Medicaid', 'text', '{"body": "## Daily habits that keep funding safe\n\n- Clock in and out at the actual time\n- Write notes the same shift, before you leave\n- Tie every note to a goal from the PCSP\n- Never share your login or sign for another worker\n- Report suspected fraud, waste, or abuse to your supervisor or to the Utah OIG\n\nWhen in doubt: ask."}'::jsonb, 9, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Summary', 'text', '{"body": "## Key takeaways\n\n- Medicaid funds DSPD services through HCBS waivers\n- Every service billed must be authorized, delivered, and documented\n- Inaccurate documentation = Medicaid fraud, with serious legal consequences\n- Your daily notes protect funding, your job, and the person''s services"}'::jsonb, 10, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('24b692eb-5d5d-4810-9f5f-88fbea850580', 'Knowledge Check: Medicaid 101', 'knowledge_check', '{"questions": [{"q": "Which program primarily funds DSPD''s HCBS?", "choices": ["Medicare", "Medicaid", "Private insurance", "Social Security"], "correct": 1, "explanation": "Medicaid funds HCBS waivers in Utah."}, {"q": "Billing for a service you didn''t deliver is Medicaid fraud.", "choices": ["True", "False"], "correct": 0, "explanation": "Billing for non-delivered services is fraud."}, {"q": "What document drives what services are authorized?", "choices": ["The DSP''s preference", "The Person-Centered Service Plan", "The agency brochure", "Whatever family asks"], "correct": 1, "explanation": "The PCSP is the legal basis for billing."}, {"q": "When should you write your service note?", "choices": ["Whenever", "Same day", "End of pay period", "Only if unusual"], "correct": 1, "explanation": "Same-day is the standard."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 11, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Learning Objectives', 'text', '{"body": "## You will learn to:\n\n- Define Protected Health Information (PHI)\n- Apply the Minimum Necessary rule\n- Recognize common HIPAA violations in DSP settings\n- Respond when family, friends, or strangers ask about a person\n- Report a suspected privacy breach"}'::jsonb, 0, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'What is HIPAA?', 'text', '{"body": "## Health Insurance Portability and Accountability Act (1996)\n\nHIPAA is the federal law that protects the privacy and security of identifiable health information. As a DSP for a Medicaid-funded agency, you are a workforce member \u2014 the rules apply to you the same way they apply to a hospital nurse.\n\nPenalties: $100 to $50,000 per record, criminal charges for intentional misuse, agency loss of Medicaid certification."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'What is PHI?', 'text', '{"body": "## PHI includes any of these when tied to a person:\n\n- Name, address, birthdate, SSN\n- Diagnoses, medications, treatment notes\n- Photos, videos, voice recordings\n- Service notes, ISP goals, incident reports\n- Billing records and Medicaid ID numbers\n\nPHI is protected on paper, on a computer, on your phone, or spoken aloud."}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Minimum Necessary', 'text', '{"body": "## Share only what is needed, with only who needs it\n\n- A pharmacist needs the medication and dose, not the full history\n- A bus driver does not need a diagnosis to provide transportation\n- A coworker on a different team does not need to know why someone went to the ER\n\nIf you wouldn''t say it in front of the person, don''t say it behind their back."}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Common HIPAA Violations', 'callout', '{"variant": "warning", "title": "Common HIPAA Violations", "body": "Real situations that have cost DSPs their jobs:\n\n- Posting a photo of a person on social media\n- Discussing a client by name in a restaurant or elevator\n- Leaving a paper notebook visible in your car\n- Texting a coworker about ''Bob''s seizure'' from your personal phone\n- Allowing a family member to read shift notes for a person they aren''t authorized for"}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Authorized vs. Unauthorized Disclosure', 'text', '{"body": "## You MAY share with:\n\n- Workforce members involved in the person''s care\n- Medical providers treating the person\n- Legally authorized guardians (verify the file)\n- DSPD, OIG, licensing during an investigation\n- Emergency responders during a life-safety event\n\n## You MAY NOT share with:\n\n- Family who are not the guardian (without written authorization)\n- Friends, neighbors, landlords\n- Your own friends, spouse, roommates\n- Anyone on social media"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Phone and Social Media', 'text', '{"body": "## Hard rules\n\n- Never take a photo or video of a person on a personal device\n- Never post about your work day in a way that could identify a client\n- Use only agency-approved systems for any communication about a person\n- Lock your phone; don''t leave it unattended where notes could be seen"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Scenario: The Curious Neighbor', 'scenario', '{"prompt": "A neighbor stops you in the parking lot: ''I saw the ambulance last night \u2014 is Mary okay?''", "context": "You support Mary in a four-bed group home. The neighbor is not on Mary''s release form.", "choices": [{"label": "''She had a seizure but she''s fine now.''", "correct": false, "feedback": "Confirming the event and diagnosis is a HIPAA violation."}, {"label": "''For privacy reasons I can''t share information about anyone here.''", "correct": true, "feedback": "Kind, firm, HIPAA-compliant."}, {"label": "''You''ll have to ask her family.''", "correct": false, "feedback": "Still confirms there is something to ask about."}]}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'If a Breach Happens', 'text', '{"body": "## Steps when PHI is accidentally disclosed\n\n1. Stop the disclosure (close door, retrieve doc, delete post)\n2. Notify your supervisor the same day\n3. Document what happened, what was disclosed, to whom\n4. The agency''s Privacy Officer assesses whether notification is required\n\n**Self-reporting is treated very differently from being caught hiding a breach.**"}'::jsonb, 8, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Summary', 'text', '{"body": "## Five rules\n\n1. Identifier + health info = PHI\n2. Share the minimum necessary\n3. No PHI on personal phones, email, or social media\n4. Verify who you''re talking to before disclosing\n5. Report suspected breaches the same day"}'::jsonb, 9, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('1248383f-5334-4d83-859c-3504d8f03021', 'Knowledge Check: HIPAA', 'knowledge_check', '{"questions": [{"q": "Which is PHI?", "choices": ["A photo", "A diagnosis", "A Medicaid ID", "All of the above"], "correct": 3, "explanation": "All identifiers tied to care are PHI."}, {"q": "You can tell a friend a funny story about ''a client'' without naming them.", "choices": ["True", "False"], "correct": 1, "explanation": "Identifying details still breach privacy."}, {"q": "Minimum Necessary means:", "choices": ["Share only what is needed", "Share everything to be safe", "Share with family", "Share in writing only"], "correct": 0, "explanation": "Disclose the least needed."}, {"q": "You email a note to the wrong address. You:", "choices": ["Hope nobody notices", "Tell supervisor same day", "Delete sent folder", "Tell recipient to delete"], "correct": 1, "explanation": "Same-day self-reporting required."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 10, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Learning Objectives', 'text', '{"body": "## You will be able to:\n\n- Define abuse, neglect, exploitation (ANE) under Utah law\n- Recognize physical, behavioral, environmental warning signs\n- Understand your mandatory reporter duty\n- Make a report to Adult Protective Services and DSPD/OIG\n- Prevent ANE through respectful support"}'::jsonb, 0, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Definitions (Utah Code 62A-3-301)', 'text', '{"body": "## Three core terms\n\n- **Abuse** \u2014 knowingly causing physical, emotional, or sexual harm; includes verbal harm, deprivation, unreasonable confinement\n- **Neglect** \u2014 failing to provide food, shelter, medical care, supervision, or services a vulnerable adult needs\n- **Exploitation** \u2014 wrongful use of a vulnerable adult''s money, property, identity, labor, or resources\n\nMost people on DSPD waivers meet the definition of ''vulnerable adult.''"}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Types of Abuse', 'text', '{"body": "## Recognize every form\n\n- **Physical** \u2014 hitting, shoving, force-feeding, rough handling\n- **Sexual** \u2014 any contact, including with someone who cannot consent\n- **Verbal/Emotional** \u2014 yelling, threats, humiliation, talking about a person as if they aren''t there\n- **Financial** \u2014 taking money/items, ''borrowing,'' using bank cards, signing names\n- **Neglect** \u2014 skipped meals, missed meds, ignored hygiene, leaving alone against the plan"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Warning Signs', 'text', '{"body": "## Physical\n\n- Unexplained bruises (clusters, fingerprint patterns, torso)\n- Burns, fractures, pressure sores, dehydration\n- Untreated medical conditions\n\n## Behavioral\n\n- Sudden fear of a specific staff member\n- Withdrawal, regression, new self-injury\n- Flinching at touch\n\n## Environmental\n\n- Missing items, unexplained gifts to staff\n- Locked refrigerators, restricted food/water"}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'You Are a Mandatory Reporter', 'callout', '{"variant": "critical", "title": "Mandatory Reporter", "body": "Under Utah Code 62A-3-305, anyone who has reason to believe a vulnerable adult has been abused, neglected, or exploited must report immediately to:\n\n- Adult Protective Services: **1-800-371-7897**\n- Law enforcement (life or safety): **911**\n- DSPD and your supervisor\n\nReasonable suspicion is enough. You are protected from retaliation."}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'How to Report', 'text', '{"body": "## Include\n\n- Name, age, address of the vulnerable adult\n- What you observed and when (facts, not interpretation)\n- Names of suspected perpetrators if known\n- Whether the person is in immediate danger\n- Your name and contact (kept confidential)\n\n## Do NOT\n\n- Investigate yourself\n- Interview the alleged abuser\n- Promise the person you''ll keep it secret\n- Delete texts, notes, or photos that might be evidence"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Scenario: Unexplained Bruise', 'scenario', '{"prompt": "During morning hygiene support you notice fingerprint-shaped bruises on the upper arm of the man you support. He looks down and says ''I''m clumsy.''", "context": "He lives in a host home setting and you are his community DSP twice a week.", "choices": [{"label": "Document the bruise and tell the host family at pickup.", "correct": false, "feedback": "Confronting potential perpetrators can endanger the person and contaminate evidence."}, {"label": "Photograph the bruise, notify your supervisor AND call APS that day.", "correct": true, "feedback": "Correct. Document, preserve evidence, report up your chain AND to APS."}, {"label": "Wait until the bruise heals to see if more appear.", "correct": false, "feedback": "Reasonable suspicion requires immediate action."}]}'::jsonb, 6, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Preventing ANE', 'text', '{"body": "## Person-centered habits\n\n- Speak to the person, not about them\n- Knock before entering bedrooms and bathrooms\n- Offer real choices throughout the day\n- Use only approved, trained interventions \u2014 and only if necessary\n- Manage your own stress; do not push through\n- Track money and belongings together with the person\n- Believe the person when they tell you something is wrong"}'::jsonb, 7, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Summary', 'text', '{"body": "## Bottom line\n\n- ANE includes physical, sexual, emotional, financial harm, and neglect\n- You are a mandatory reporter \u2014 call APS at 1-800-371-7897\n- Reasonable suspicion is enough\n- Document facts, preserve evidence, do not investigate\n- Prevention starts with respect, choice, supervision"}'::jsonb, 8, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('765ec39a-02bc-4b8b-bf39-6235327898bc', 'Knowledge Check: ANE', 'knowledge_check', '{"questions": [{"q": "Who must report suspected abuse of a vulnerable adult in Utah?", "choices": ["Only nurses", "Only managers", "Anyone with reasonable suspicion", "Only law enforcement"], "correct": 2, "explanation": "All persons are mandatory reporters."}, {"q": "You suspect a coworker is taking a client''s money. You:", "choices": ["Confront the coworker", "Wait for proof", "Report to supervisor AND APS", "Tell the person to hide their wallet"], "correct": 2, "explanation": "Report up your chain and to APS."}, {"q": "Talking about a person as if they aren''t in the room can be emotional abuse.", "choices": ["True", "False"], "correct": 0, "explanation": "Disrespectful communication is emotional abuse."}, {"q": "What number reports suspected abuse of a vulnerable adult in Utah?", "choices": ["911 only", "1-800-371-7897 (APS)", "Fire department", "Nobody"], "correct": 1, "explanation": "APS: 1-800-371-7897."}], "passing_score": 80, "max_attempts": 3}'::jsonb, 9, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Learning Objectives', 'text', '{"body": "## You will be able to:\n\n- Explain the federal HCBS Settings Rule (42 CFR 441.301(c)(4))\n- Identify the five required qualities of an HCBS setting\n- Recognize institutional practices that violate the rule\n- Document a person-specific rights modification correctly\n- Apply the rule in real DSP work \u2014 visitors, food, schedules, locks, choices"}'::jsonb, 0, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Why The Rule Exists', 'text', '{"body": "## The promise of HCBS\n\nMedicaid HCBS waivers exist so people can live in communities instead of institutions. In 2014 CMS finalized the Settings Rule because too many ''community'' homes still operated like mini-institutions \u2014 fixed wake-up times, locked refrigerators, no visitors, group-only outings.\n\nIf Medicaid is paying for a setting, that setting must actually feel like a home or a real job."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'The Five Required Qualities', 'text', '{"body": "## Every HCBS setting must:\n\n1. **Be integrated in the community**\n2. **Support choice** of where to live and with whom\n3. **Ensure rights** of privacy, dignity, respect, freedom from coercion\n4. **Optimize autonomy** in daily activities and routines\n5. **Facilitate informed choice** in services and providers"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Residential Setting Requirements', 'text', '{"body": "## In a person''s home, they MUST be able to:\n\n- Have a lease or written agreement with tenant protections\n- Lock their own bedroom door\n- Choose their roommate when sharing\n- Furnish and decorate their bedroom\n- Control their own schedule (sleeping, eating, activities)\n- Have visitors at any time\n- Access food at any time\n- Have physical access to all common areas"}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Institutional Red Flags', 'callout', '{"variant": "warning", "title": "Institutional Red Flags", "body": "These VIOLATE the rule unless individually justified and documented in the PCSP:\n\n- ''Lights out at 10 PM'' house rule\n- Locked refrigerator or pantry for all residents\n- ''No visitors after 8 PM'' blanket policy\n- Mandatory group activities\n- Single bath schedule for everyone\n- Staff entering bedrooms without knocking"}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Rights Modifications', 'text', '{"body": "## A right can be modified only when:\n\n- There is a specific assessed need (health/safety)\n- Positive interventions and less-restrictive options were tried first\n- The modification is in writing in the PCSP\n- The person (or guardian) gave informed consent\n- Progress is reviewed regularly to fade the restriction\n\nA locked pantry overnight may be appropriate for one person with Prader-Willi syndrome \u2014 but only with a documented plan; never a house-wide rule."}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Scenario: Visitor Restrictions', 'scenario', '{"prompt": "Night staff tells you: ''House rule \u2014 no visitors after 8 PM.''", "context": "There is no individual rights modification in any resident''s PCSP.", "choices": [{"label": "Follow the house rule.", "correct": false, "feedback": "Blanket visitor rules violate the Settings Rule."}, {"label": "Welcome any visitor unless a PCSP restricts it, and report the rule to your supervisor.", "correct": true, "feedback": "Correct. Visitors are each resident''s choice."}, {"label": "Ask the visitor to come back tomorrow.", "correct": false, "feedback": "Still a violation."}]}'::jsonb, 6, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Daily Practices', 'text', '{"body": "## DSP examples\n\n- Ask, don''t tell, what time the person wants to wake up\n- Offer real meal choices\n- Knock and wait every time\n- Support the person to go to community places they pick\n- Help with community jobs, library cards, gym memberships\n- Document the person''s choices in the daily note"}'::jsonb, 7, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Summary', 'text', '{"body": "## Remember\n\n- HCBS-funded settings must feel like a real home or job\n- Five qualities: integration, choice, rights, autonomy, informed choice\n- Bedroom locks, visitors anytime, food access, own schedule are required\n- Restrictions are allowed only with a documented, person-specific plan"}'::jsonb, 8, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('7564a669-9eb4-4216-86cd-e379253b1a2f', 'Knowledge Check: HCBS', 'knowledge_check', '{"questions": [{"q": "Which is NOT a required quality?", "choices": ["Community integration", "Rights and dignity", "Mandatory group activities", "Informed choice"], "correct": 2, "explanation": "Mandatory group activities are institutional."}, {"q": "A blanket ''no visitors after 8 PM'' rule is allowed if the house manager creates it.", "choices": ["True", "False"], "correct": 1, "explanation": "Blanket restrictions violate the rule."}, {"q": "When may a right be restricted?", "choices": ["When staff find it inconvenient", "When documented in PCSP with consent and a fade plan", "Never", "When agency policy says so"], "correct": 1, "explanation": "Person-specific, documented, with consent."}, {"q": "Residents must be able to:", "choices": ["Lock their bedroom", "Have visitors any time", "Choose when to eat", "All of the above"], "correct": 3, "explanation": "All three are required."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 9, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'Learning Objectives', 'text', '{"body": "## You will be able to:\n\n- Define trauma and its impact on the brain and behavior\n- Apply the six principles of trauma-informed care\n- Recognize trauma responses\n- Use language and practices that promote safety and trust"}'::jsonb, 0, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'What is Trauma?', 'text', '{"body": "## An event AND a response\n\nTrauma results from events that are physically or emotionally harmful with lasting effects on functioning and well-being. People with IDD and ABI experience trauma at significantly higher rates \u2014 from medical procedures, institutional placement, abuse, loss of family, restrictive interventions.\n\nTrauma changes how the brain responds to stress. ''Overreaction'' may be a survival response."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'Six Principles (SAMHSA)', 'text', '{"body": "## The framework\n\n1. **Safety** \u2014 physical and emotional\n2. **Trustworthiness & transparency**\n3. **Peer support**\n4. **Collaboration & mutuality**\n5. **Empowerment, voice & choice**\n6. **Cultural, historical & gender awareness**"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'Recognize Trauma Responses', 'text', '{"body": "## The 4 F''s\n\n- **Fight** \u2014 aggression, yelling, throwing\n- **Flight** \u2014 running, leaving, hiding\n- **Freeze** \u2014 silent, motionless, dissociating\n- **Fawn** \u2014 over-compliance, people-pleasing\n\nThese are nervous-system responses, not choices. Punishment makes them worse; safety and predictability make them better."}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'From What''s Wrong to What Happened', 'callout', '{"variant": "info", "title": "Reframe", "body": "A trauma-informed DSP asks ''what has this person lived through, and what is their behavior telling me they need right now?'' instead of ''why is this person acting out?''"}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'Practices in Daily Work', 'text', '{"body": "## Do\n\n- Keep routines predictable; explain changes in advance\n- Offer choice in small everyday decisions\n- Use a calm, low tone; soften posture\n- Give space\n- Honor the person''s ''no''\n\n## Don''t\n\n- Surprise the person with physical touch\n- Use commands when a request works\n- Stand over or block the person\n- Discuss their history in front of them"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'Summary', 'text', '{"body": "## Core idea\n\nTrauma changes the brain. Predictability, choice, respect, and a calm presence are the best clinical tools you have."}'::jsonb, 6, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('b0dfbaac-7b0e-4b0f-98a5-fad8021461ac', 'Knowledge Check: Trauma-Informed', 'knowledge_check', '{"questions": [{"q": "Which is one of the six trauma-informed principles?", "choices": ["Discipline", "Empowerment, voice & choice", "Strict routine", "Restraint training"], "correct": 1, "explanation": "Empowerment, voice & choice."}, {"q": "A person freezes when redirected. Most likely:", "choices": ["Manipulation", "A trauma response", "Defiance", "Boredom"], "correct": 1, "explanation": "Freeze is a 4F response."}, {"q": "Reframe ''What''s wrong with you?'' to:", "choices": ["''Why won''t you behave?''", "''What happened to you?''", "''Who is responsible?''", "''What do you want?''"], "correct": 1, "explanation": "The foundational reframe."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Define Positive Behavior Support (PBS)\n- Identify the four functions of behavior\n- Use proactive strategies that prevent challenging behavior\n- Respond to behavior in a way that respects dignity"}'::jsonb, 0, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'What Is PBS?', 'text', '{"body": "## A values-based, evidence-based approach\n\nPBS assumes:\n\n- All behavior is communication\n- Behavior serves a purpose\n- Punishment-based approaches harm the person and rarely change behavior long-term\n- Teaching new skills and changing environments reduces challenging behavior\n\nPBS replaces punishment with **prevention + teaching + reinforcement**."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Four Functions of Behavior', 'text', '{"body": "## Behavior usually serves one (or more) of:\n\n1. **Attention** \u2014 social interaction\n2. **Escape/avoidance** \u2014 out of a demand\n3. **Access to tangibles** \u2014 obtain a preferred item\n4. **Sensory** \u2014 feel or stop feeling a sensation\n\nLook at antecedent (before) and consequence (after) to identify the function."}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Proactive Strategies', 'text', '{"body": "## Prevent before it happens\n\n- Build rapport when the person is calm\n- Offer real choices throughout the day\n- Use visual schedules and warnings before transitions\n- Honor preferences in food, music, clothing\n- Build in breaks before fatigue\n- Teach replacement skills (asking for a break, requesting attention)"}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Avoid Punishment-Based Reactions', 'callout', '{"variant": "warning", "title": "Avoid Aversives", "body": "Withholding favorite items, raising your voice, time-outs in a locked room, physical restraint, withdrawing affection \u2014 these are NOT positive supports. Most are prohibited in DSPD settings without a written, approved BSP and consent."}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Responding in the Moment', 'text', '{"body": "## Framework\n\n1. Ensure safety\n2. Reduce demands\n3. Give space and time\n4. Offer a choice that meets the function\n5. Reconnect when calm \u2014 don''t lecture\n\nAfter: document, debrief, identify the antecedent to prevent next time."}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Working a Behavior Support Plan', 'text', '{"body": "## If the person has a BSP\n\n- Read it before your first shift\n- Follow proactive strategies exactly\n- Use the same prompts, scripts, reinforcers as the team\n- Document each incident as specified\n- Bring suggestions to the team \u2014 never freelance"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Summary', 'text', '{"body": "## Hold these\n\n- Behavior is communication\n- Identify the function before responding\n- Prevention + teaching + reinforcement beats punishment\n- Follow the written BSP \u2014 consistency matters more than cleverness"}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('112fd415-8707-4a63-8dfb-5c2f642b586d', 'Knowledge Check: PBS', 'knowledge_check', '{"questions": [{"q": "Which is NOT a function of behavior?", "choices": ["Attention", "Escape", "Sensory", "Revenge"], "correct": 3, "explanation": "Four functions: attention, escape, tangibles, sensory."}, {"q": "The first step of PBS is:", "choices": ["Punish", "Understand the function", "Restrain", "Ignore"], "correct": 1, "explanation": "Understand first, then respond."}, {"q": "Withholding a preferred item is a positive behavior support.", "choices": ["True", "False"], "correct": 1, "explanation": "That is an aversive."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Identify common seizure types\n- Provide safe support during a seizure\n- Recognize when a seizure becomes a 911 emergency\n- Document the event accurately"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'What Is a Seizure?', 'text', '{"body": "## A burst of abnormal electrical activity in the brain\n\nSeizures look very different depending on the brain area involved \u2014 from full-body shaking to a blank stare. Many people with IDD and ABI have a known seizure disorder; always read their plan."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'Types You May See', 'text', '{"body": "## Generalized tonic-clonic (grand mal)\n\n- Loss of consciousness, stiffening, rhythmic jerking\n- May fall, lose bladder control, bite tongue\n\n## Absence (petit mal)\n\n- Brief blank stare, eye fluttering, seconds long\n\n## Focal (partial)\n\n- Twitching of one body part, sensory changes, repetitive movements"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'Safe Support \u2014 DO', 'text', '{"body": "## During the seizure\n\n- Stay with the person\n- Time it (start your watch)\n- Guide them to the floor if standing\n- Cushion the head\n- Loosen anything tight around the neck\n- Turn on their side once jerking stops\n- Speak calmly afterward"}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'Never Do These', 'callout', '{"variant": "critical", "title": "Never", "body": "- Do NOT put anything in the mouth (they cannot swallow their tongue)\n- Do NOT restrain movements\n- Do NOT give food, water, or meds until fully alert\n- Do NOT leave them alone"}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'Call 911 When\u2026', 'text', '{"body": "## Activate 911 immediately if:\n\n- Seizure lasts more than **5 minutes**\n- A second seizure follows without full recovery\n- The person is injured\n- It happens in water\n- It is the first known seizure\n- Breathing does not return to normal\n- The person has diabetes, is pregnant, or has a known cardiac condition"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'After the Seizure', 'text', '{"body": "## Post-ictal care\n\n- Keep the area calm\n- Allow rest\n- Re-orient gently\n- Notify nurse/supervisor\n- Document: start/end time, type observed, recovery, injuries, any rescue meds given"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'Summary', 'text', '{"body": "## Five things\n\n1. Stay, time, cushion, side, speak calmly\n2. Nothing in the mouth, no restraint\n3. 5+ minutes = 911\n4. Document everything\n5. Follow the person''s specific protocol"}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('2d3a85b1-36ec-4d4a-afb6-ab90aa2405fd', 'Knowledge Check: Seizure', 'knowledge_check', '{"questions": [{"q": "911 threshold for a tonic-clonic seizure?", "choices": ["1 min", "3 min", "5 min", "10 min"], "correct": 2, "explanation": "5+ minutes = status epilepticus."}, {"q": "During a seizure you should:", "choices": ["Put a spoon in their mouth", "Hold arms still", "Cushion head and turn on side", "Pour water on face"], "correct": 2, "explanation": "Protect head, use recovery position."}, {"q": "A person can swallow their tongue during a seizure.", "choices": ["True", "False"], "correct": 1, "explanation": "Myth \u2014 never put anything in the mouth."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Identify people at higher risk of choking\n- Recognize partial vs. complete airway obstruction\n- Implement diet textures and meal supervision per the person''s plan\n- Respond correctly when choking occurs"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Risk Factors', 'text', '{"body": "## Higher risk\n\n- Dysphagia (swallowing difficulties)\n- Cerebral palsy, ABI, advanced dementia\n- Missing teeth, poor dentition\n- Medications that reduce saliva\n- Rapid eating, large bites, eating while lying down\n- History of aspiration pneumonia\n\nAlways check the person''s plan for diet texture and liquid consistency."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'High-Risk Foods', 'text', '{"body": "## Common culprits\n\n- Hot dogs, sausages cut in rounds\n- Whole grapes, cherry tomatoes\n- Popcorn, nuts, seeds\n- Hard candy, gum\n- Sticky peanut butter (plain)\n- Tough or stringy meat\n- Bread in large bites"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Mealtime Supervision', 'text', '{"body": "## Best practices\n\n- Sit upright at 90 degrees\n- Small bites, full chew between\n- No talking with food in mouth\n- One bite at a time\n- Eyes on the person \u2014 not phone or notes\n- Stay upright at least 30 minutes after eating"}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Recognize the Signs', 'callout', '{"variant": "critical", "title": "Partial vs. Complete", "body": "**Partial obstruction**: coughing, gagging, wheezing \u2014 encourage them to keep coughing.\n\n**Complete obstruction**: cannot speak/cough/breathe; clutches throat; skin turns blue \u2014 life-threatening. Begin back blows and abdominal thrusts and call 911."}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Response \u2014 Conscious Adult', 'text', '{"body": "## Heimlich maneuver\n\n1. Ask ''Are you choking?'' \u2014 if they nod and cannot speak, act\n2. Stand behind, fist above the navel, other hand over fist\n3. Quick upward thrusts until object expels or person becomes unresponsive\n4. If unresponsive: lower to ground, begin CPR, call 911\n\nUse only the technique you are currently certified in."}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Documentation', 'text', '{"body": "## After any choking event\n\n- Notify nurse/supervisor immediately\n- Document on incident report: food, signs, response, outcome\n- A medical eval is warranted even if the object was expelled (aspiration risk)\n- Review whether diet texture or supervision plan needs updating"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Summary', 'text', '{"body": "## Prevention first\n\n- Know each person''s diet texture\n- Eyes on the person during every meal\n- Recognize partial vs. complete obstruction\n- Use trained techniques; call 911 when in doubt"}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('439ab025-1780-4f07-a2d9-5fffc3ab47a5', 'Knowledge Check: Choking', 'knowledge_check', '{"questions": [{"q": "A person is coughing hard but breathing. You:", "choices": ["Slap back hard", "Encourage them to keep coughing", "Give water", "Start chest thrusts"], "correct": 1, "explanation": "A strong cough is the most effective response."}, {"q": "Which is a high-risk food?", "choices": ["Whole grapes", "Diced cooked carrots", "Yogurt", "Mashed potatoes"], "correct": 0, "explanation": "Whole grapes are top hazards."}, {"q": "Best position to eat:", "choices": ["Reclined", "Upright 90 degrees", "Lying on side", "Standing"], "correct": 1, "explanation": "Upright reduces aspiration risk."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Identify reportable incidents under DSPD rules\n- Complete an incident report that meets state requirements\n- Understand the difference between agency, DSPD, and OIG/APS reporting\n- Meet the timeline expectations"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'What Counts as an Incident', 'text', '{"body": "## DSPD-reportable\n\n- Death\n- Serious injury, hospitalization, ER visit\n- ANE allegations\n- Medication error (wrong med/dose/missed/person/time)\n- Restraint or restrictive intervention\n- Elopement / missing person\n- Significant property damage\n- Police involvement / arrest\n- Suicide attempt or threat\n- Fire, evacuation, disaster"}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'Timelines', 'text', '{"body": "## Know your clock\n\n- **Immediate verbal**: ANE, death, serious injury, missing person, suicide attempt, restraint\n- **24 hours**: written DSPD critical incident report\n- **7 days** (typical): investigation, root cause, corrective plan\n\nLate reporting is itself a citable deficiency."}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'When in Doubt, Report', 'callout', '{"variant": "warning", "title": "DSPD Reportable", "body": "It is far better to file a report that turns out to be minor than to fail to file one that turns out to be significant. DSPD reviews patterns to catch systemic risk."}'::jsonb, 3, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'Writing a Good Report', 'text', '{"body": "## 5 Ws + H\n\n- Who, What, Where, When, Why (known antecedents only), How\n\n**Facts only. No opinions, diagnoses, or blame.**"}'::jsonb, 4, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'Scenario: Medication Error', 'scenario', '{"prompt": "At 7:30 AM you give a morning pill. At 8:00 AM you realize it was the other resident''s card. The person feels fine.", "context": "Both residents take similar pills but different doses.", "choices": [{"label": "Wait until lunch to see if symptoms appear.", "correct": false, "feedback": "Med errors are immediately reportable."}, {"label": "Call the nurse/Poison Control, document, notify supervisor, complete a med error report.", "correct": true, "feedback": "Correct."}, {"label": "Document quietly and tell next shift to watch.", "correct": false, "feedback": "Failure to escalate is itself a violation."}]}'::jsonb, 5, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'Who Else Gets Notified', 'text', '{"body": "## Layered reporting\n\n- Agency supervisor/on-call \u2014 immediately\n- Nurse \u2014 medical incidents\n- Family/guardian \u2014 per PCSP preferences\n- DSPD \u2014 critical incident report\n- APS (1-800-371-7897) \u2014 suspected ANE\n- 911 \u2014 crimes, life-safety\n- OIG \u2014 suspected Medicaid fraud"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'Summary', 'text', '{"body": "## Bottom line\n\n- Know the reportable categories\n- Verbal immediate + written same-day for critical events\n- Facts only\n- Notify the right people in the right order\n- When in doubt, report"}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('cbe7e7c9-8779-480c-927a-2ed37116ed7e', 'Knowledge Check: Incident Reporting', 'knowledge_check', '{"questions": [{"q": "Which is NOT a DSPD-reportable incident?", "choices": ["Med error", "Serious injury", "Routine hygiene support", "Physical restraint"], "correct": 2, "explanation": "Routine support is not an incident."}, {"q": "How fast must a critical incident be written up?", "choices": ["1 hour", "24 hours", "7 days", "End of month"], "correct": 1, "explanation": "24-hour standard."}, {"q": "An incident report should include:", "choices": ["Your opinion about blame", "A diagnosis", "Observable facts and times", "A guess at motive"], "correct": 2, "explanation": "Facts only."}], "passing_score": 80, "max_attempts": 3}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Recognize warning signs of suicide risk\n- Ask directly and safely about suicide\n- Connect the person to immediate help\n- Document and follow up"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'Why DSPs Matter', 'text', '{"body": "## You may be the closest person\n\nPeople with IDD and ABI die by suicide at higher rates than the general population. DSPs often spend more daily time with the person than family or clinicians \u2014 making you most likely to notice the early signs."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'Warning Signs', 'text', '{"body": "## Watch and listen for\n\n- Talking about wanting to die, being a burden, having no reason to live\n- Giving away possessions, saying goodbye\n- Increased substance use\n- Withdrawing, dramatic mood changes\n- Sudden calm after depression\n- Looking for means (pills, weapons, plans)\n- Previous attempts (biggest risk factor)"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'Ask Directly', 'callout', '{"variant": "info", "title": "Ask Directly", "body": "Asking about suicide does NOT plant the idea. It opens the door.\n\nUse plain words: ''Are you thinking about killing yourself?''\n\nSoft phrases like ''doing something silly'' are not clear enough."}'::jsonb, 3, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'Ask, Listen, Connect', 'text', '{"body": "## In the moment\n\n1. **ASK** directly\n2. **LISTEN** without judgment; no secrecy promises\n3. **STAY** with the person\n4. **SECURE means** \u2014 lock up pills, sharps, firearms\n5. **CONNECT** \u2014 call **988**, or 911 if immediate danger\n6. **NOTIFY** supervisor and on-call clinician\n7. **DOCUMENT** the person''s words"}'::jsonb, 4, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'After the Crisis', 'text', '{"body": "## Continued safety\n\n- Follow the clinician''s safety plan\n- Continue close monitoring as directed\n- Maintain a calm, hopeful tone\n- The 30\u201390 days after a crisis is the highest-risk window\n- Take care of yourself \u2014 debrief with supervisor or EAP"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'What NOT to Do', 'text', '{"body": "## Things that increase risk\n\n- Promise not to tell anyone\n- Leave them alone to ''cool off''\n- Argue them out of their feelings\n- Minimize (''it''s not that bad'')\n- Express anger or panic\n- Use casual language"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'Summary', 'text', '{"body": "## Remember\n\n- Take every statement seriously\n- Ask directly\n- Listen, stay, secure means, connect to **988**\n- Document the person''s own words\n- Follow the safety plan"}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('14367a5d-0135-4771-8b13-aca454ffdda7', 'Knowledge Check: Suicide Prevention', 'knowledge_check', '{"questions": [{"q": "Asking someone directly about suicide can put the idea in their head.", "choices": ["True", "False"], "correct": 1, "explanation": "Asking reduces risk and opens the door."}, {"q": "What number is the Suicide & Crisis Lifeline?", "choices": ["911", "988", "211", "311"], "correct": 1, "explanation": "988."}, {"q": "Person says they want to end their life and asks you to keep it secret. You:", "choices": ["Promise secrecy", "Refuse and connect them to help", "Change the subject", "Wait until next shift"], "correct": 1, "explanation": "You cannot keep a life-safety secret."}], "passing_score": 80, "max_attempts": 3}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Recognize when to call 911\n- Differentiate medical, behavioral, and mental health emergencies\n- Activate the emergency response chain\n- Provide useful information to dispatchers"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'When to Call 911 \u2014 Medical', 'text', '{"body": "## Call 911 immediately for:\n\n- Difficulty breathing, choking that cannot be cleared\n- Chest pain with sweating or weakness\n- Stroke signs \u2014 F.A.S.T. (Face droop, Arm weakness, Speech difficulty, Time to call)\n- Seizure > 5 minutes or back-to-back\n- Severe bleeding\n- Severe allergic reaction (anaphylaxis)\n- Unresponsiveness\n- Suspected overdose or poisoning\n- Major fall with head/neck/back injury\n- Large burns or on face/hands/genitals"}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'When to Call 911 \u2014 Safety / Mental Health', 'text', '{"body": "## Activate 911 for\n\n- Active suicide attempt or means in hand\n- Threat with a weapon\n- Active assault\n- Fire, gas leak, structural collapse\n- Missing person in danger (cold, heat, water, traffic)\n- Behavioral crisis with serious injury risk"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'Don''t Drive Them Yourself', 'callout', '{"variant": "warning", "title": "Don''t Drive Them", "body": "If the person needs emergency medical care, do NOT load them in your car. EMS begins treatment in the ambulance; driving private vehicles delays care and exposes you to liability."}'::jsonb, 3, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'How to Make the Call', 'text', '{"body": "## Be ready with\n\n1. Exact address\n2. What is happening, when it started\n3. Person''s age, conditions, allergies, current medications\n4. Any DNR or POLST\n5. Best entry point and your callback number\n\nStay on the line; send someone to flag down the ambulance."}'::jsonb, 4, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'While Waiting', 'text', '{"body": "## Provide trained care\n\n- Open the airway (head-tilt unless trauma)\n- Begin CPR if no pulse / not breathing normally\n- Control bleeding with direct pressure\n- Do not move if spinal injury possible\n- Stay calm\n- Gather meds, ID, insurance, ISP one-page profile"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'After the Emergency', 'text', '{"body": "## Required follow-up\n\n- Notify supervisor, on-call, family/guardian\n- Complete a critical incident report within 24 hours\n- Update records with hospital paperwork\n- Debrief \u2014 emergency response is stressful"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'Summary', 'text', '{"body": "## Five rules\n\n1. Recognize 911 categories\n2. Don''t drive them yourself\n3. Be ready with address, conditions, meds\n4. Provide trained care while waiting\n5. Document the incident the same day"}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('3bbee3b5-8cb7-4b48-bb0d-9de2f9ef26f5', 'Knowledge Check: 911', 'knowledge_check', '{"questions": [{"q": "Which is a 911 emergency?", "choices": ["Mild headache", "Sudden chest pain with shortness of breath", "Minor cut", "Tiredness"], "correct": 1, "explanation": "Possible cardiac event."}, {"q": "Faster to drive the person to the ER yourself?", "choices": ["True", "False"], "correct": 1, "explanation": "EMS begins treatment in the ambulance."}, {"q": "F.A.S.T. is used to recognize:", "choices": ["Stroke", "Choking", "Burns", "Seizure"], "correct": 0, "explanation": "Stroke."}], "passing_score": 80, "max_attempts": 3}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Recognize the phases of a behavioral crisis\n- Use de-escalation techniques\n- Know when to call a doctor vs. mental health professional vs. 911"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'The Crisis Cycle', 'text', '{"body": "## Five phases\n\n1. **Baseline** \u2014 calm\n2. **Trigger** \u2014 stressor\n3. **Escalation** \u2014 agitation, pacing\n4. **Crisis** \u2014 loss of control\n5. **Recovery** \u2014 fatigue, often shame; do NOT lecture in recovery"}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'De-Escalation Techniques', 'text', '{"body": "## In the moment\n\n- Lower your voice, slow your speech\n- Increase physical space (one arm''s length minimum)\n- Drop demands\n- Validate (''I can see you''re really upset'')\n- Offer choice (''step outside or sit on the couch?'')\n- One staff voice \u2014 don''t crowd\n- Use silence"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'Your Calm Is the Tool', 'callout', '{"variant": "success", "title": "Best Practice", "body": "Your own regulated nervous system is the #1 de-escalation tool. If you escalate, the situation will escalate."}'::jsonb, 3, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'When to Call a Doctor', 'text', '{"body": "## Non-emergency medical contact for\n\n- New persistent pain, fever > 100.4\u00b0F > 24 hours\n- Vomiting/diarrhea > 24 hours, dehydration signs\n- New rash, persistent cough, swelling\n- Med side effects (non-life-threatening)\n- Worsening of a chronic condition\n- Wound that won''t heal\n\nUse the nurse line after hours. Document symptoms, vitals, provider response."}'::jsonb, 4, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'When to Call a Mental Health Professional', 'text', '{"body": "## Reach out (non-911) when you see\n\n- Worsening anxiety, depression, psychosis\n- Multi-night sleep disruption\n- Increased frequency/intensity of behaviors\n- Loss of mastered skills\n- Substance use changes\n- Statements about wanting to be ''gone'' that aren''t immediate crisis\n\nChannels: agency clinician, prescriber, Mobile Crisis Outreach, **988** for any crisis-level concern."}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'Escalation Decision Tree', 'text', '{"body": "## Hierarchy\n\n- Active danger to life/self/others \u2192 **911**\n- Mental health crisis \u2192 **988** or Mobile Crisis\n- New medical symptom needing same-day eval \u2192 nurse line / doctor\n- Worsening mental health, non-crisis \u2192 clinician / case manager\n- Behavior consistent with BSP \u2192 follow the plan, debrief"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'After the Crisis', 'text', '{"body": "## Recovery phase support\n\n- Restore quiet, predictable environment\n- Offer water, snack, low-stimulation activity\n- Do NOT problem-solve for at least 30 minutes\n- Document objectively; identify the antecedent\n- Debrief with team; update BSP if needed"}'::jsonb, 7, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'Summary', 'text', '{"body": "## Hierarchy\n\n**911 \u2192 988 \u2192 Doctor/Nurse \u2192 Clinician \u2192 BSP/Supervisor**\n\nYour calm is the strongest tool. Recovery phase needs quiet, not lectures."}'::jsonb, 8, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('9868eb79-11e2-4e1c-9d86-acf4b2019538', 'Knowledge Check: De-Escalation', 'knowledge_check', '{"questions": [{"q": "During escalation you should:", "choices": ["Add staff to crowd them", "Increase demands", "Lower your voice and give space", "Restrain immediately"], "correct": 2, "explanation": "Calm tone, more space, fewer demands."}, {"q": "Non-life-threatening mental health concern \u2192 best contact:", "choices": ["911", "988", "Police non-emergency", "Fire department"], "correct": 1, "explanation": "988 covers any mental health crisis level."}, {"q": "Recovery phase calls for:", "choices": ["Lecture", "Quiet, low-stimulation", "Social media post", "Continue demand"], "correct": 1, "explanation": "Recovery needs calm."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 9, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Recognize when a person is ''missing'' under DSPD rules\n- Begin the search safely and immediately\n- Notify the correct chain\n- Document for the critical incident report"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'What Counts as Missing', 'text', '{"body": "## A person is missing when\n\n- Not where scheduled and not accounted for by plan\n- Leaves a setting without staff knowledge against their plan\n- Does not return from a community outing as expected\n\nThere is no ''wait and see'' grace period for people whose plans require constant supervision."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'Immediate Response (first 5 min)', 'text', '{"body": "## Act fast\n\n1. Confirm \u2014 check all rooms, yard, bathrooms\n2. Note time last seen and clothing\n3. Check usual exits and known destinations\n4. Notify supervisor / on-call\n5. If elopement risk or any danger (cold, water, traffic, medical), call **911** immediately"}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'Don''t Search Alone Forever', 'callout', '{"variant": "warning", "title": "Time Lost = Risk", "body": "Sweep the immediate area for no more than ~10 minutes. After that, call law enforcement. Especially in extreme weather or near traffic."}'::jsonb, 3, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'Info for 911 / Law Enforcement', 'text', '{"body": "## Have ready\n\n- Full name, DOB, photo\n- Description: height, weight, clothing, features\n- Diagnoses, communication style, sensory needs\n- Medications needed within 24 hours\n- Whether they respond to their name\n- Known favorite places, prior elopement patterns\n- Whether the person is considered endangered"}'::jsonb, 4, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'After the Person Is Found', 'text', '{"body": "## Care first, then document\n\n- Medical eval \u2014 injury, exposure, dehydration\n- Calm reunion; no scolding\n- Critical incident report within 24 hours\n- Root cause: what allowed it? What prevents the next?\n- Update BSP and environmental controls"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'Summary', 'text', '{"body": "## Remember\n\n- Missing = act now, no waiting period\n- Sweep, notify, escalate to 911 if any danger\n- Provide responders with photo, description, conditions, meds\n- Medical eval and incident report after reunion"}'::jsonb, 6, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('a21a7a19-0f31-4f75-a524-cdcd13dfb34d', 'Knowledge Check: Missing Person', 'knowledge_check', '{"questions": [{"q": "You realize the person is not in the house. First step:", "choices": ["Wait 30 minutes", "Confirm, notify supervisor; 911 if any danger", "Drive to their family", "Post on social media"], "correct": 1, "explanation": "Confirm, notify, escalate."}, {"q": "When should law enforcement be called?", "choices": ["After several hours", "Immediately if endangered", "Never", "Only if family says so"], "correct": 1, "explanation": "Endangered = immediate 911."}, {"q": "After the person is safely found:", "choices": ["Skip the report", "Document a critical incident within 24 hours", "Email family only", "Wait a week"], "correct": 1, "explanation": "Critical incident report required."}], "passing_score": 75, "max_attempts": 3}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Learning Objectives', 'text', '{"body": "## You will:\n\n- Tell medical from behavioral from mental health emergencies\n- Choose the correct contact: 911, 988, nurse, doctor, clinician\n- Document the symptom or behavior and the contact you made"}'::jsonb, 0, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Medical vs. Mental Health vs. Behavioral', 'text', '{"body": "## Triage\n\n- **Medical** \u2014 body in distress (chest pain, breathing, seizure, bleeding, fever, severe pain)\n- **Mental health** \u2014 mood, thoughts, perception\n- **Behavioral** \u2014 actions in the moment, often driven by an unmet need or medical/mental health issue\n\nAlways rule out medical first."}'::jsonb, 1, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Call a Doctor / Nurse Line When\u2026', 'text', '{"body": "## Non-emergency medical input\n\n- Fever > 100.4\u00b0F > 24 hours\n- New rash, swelling, persistent cough\n- Vomiting/diarrhea > 24 hours\n- Suspected UTI signs (frequency, cloudy urine, new confusion)\n- Wound not healing\n- Uncomfortable med side effects\n- Worsening chronic condition\n\nDocument vitals, symptom timeline, provider instruction."}'::jsonb, 2, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Call a Mental Health Professional When\u2026', 'text', '{"body": "## Behavioral / mental health concerns\n\n- Increased withdrawal, depression, hopelessness\n- New or worsening anxiety, panic, paranoia\n- Sleep deeply disrupted multiple nights\n- Sudden change in functioning\n- Wanting to die statements not at immediate intent (those \u2192 988/911)\n- Substance use changes\n- Behavior cycles intensifying\n\nChannels: agency clinician, prescriber, Mobile Crisis, or **988**."}'::jsonb, 3, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Call 911 When\u2026', 'callout', '{"variant": "critical", "title": "Life or Limb", "body": "- Not breathing / no pulse\n- Chest pain with sweating or pallor\n- Stroke signs (F.A.S.T.)\n- Seizure > 5 min or repeated\n- Active suicide attempt or weapon\n- Severe bleeding, severe burns, suspected overdose\n- Anaphylaxis\n- Unresponsiveness"}'::jsonb, 4, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Decision Tree', 'text', '{"body": "## Every time\n\n1. Life or limb at immediate risk? \u2192 **911**\n2. Mental health crisis (suicidal, psychotic, severe panic)? \u2192 **988** or Mobile Crisis\n3. Medical symptom needing same-day eval? \u2192 nurse line / doctor\n4. Worsening mental health, not crisis? \u2192 agency clinician\n5. Behavioral and consistent with BSP? \u2192 follow plan, debrief"}'::jsonb, 5, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Documenting the Escalation', 'text', '{"body": "## Every contact must be recorded\n\n- What you observed (symptom/behavior, objective terms)\n- Time observed\n- Who you called, time of call, who answered\n- Instructions given\n- Outcome and follow-up plan\n- Anyone else notified (family, guardian, on-call)"}'::jsonb, 6, 4, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Summary', 'text', '{"body": "## Hierarchy\n\n**911 \u2192 988 \u2192 Doctor/Nurse \u2192 Clinician \u2192 BSP/Supervisor**\n\nRule out medical causes for behavior. When in doubt, escalate up."}'::jsonb, 7, 3, true);
INSERT INTO lessons (module_id, title, lesson_type, data, order_index, duration_minutes, required) VALUES ('6e17b27c-eb73-4d3d-8fac-dfc71f905a00', 'Knowledge Check: Escalation', 'knowledge_check', '{"questions": [{"q": "Suddenly more confused, has fever, refusing fluids. Best first:", "choices": ["988", "Nurse / doctor (rule out infection)", "Wait until tomorrow", "Restrain"], "correct": 1, "explanation": "Confusion + fever \u2192 medical eval (often UTI)."}, {"q": "Person feels deeply hopeless, denies a plan. Best contact:", "choices": ["911", "988 or agency clinician", "Wait until next appt", "Nothing"], "correct": 1, "explanation": "Below 911 threshold = 988 / clinician same day."}, {"q": "Behavior changes can be caused by medical issues.", "choices": ["True", "False"], "correct": 0, "explanation": "Always rule out medical causes."}], "passing_score": 80, "max_attempts": 3}'::jsonb, 8, 3, true);
